function countHops(a) {
  let i = 0;
  let hops = 0;
  while (i < a.length) {
    i += a[i];
    hops++;
  }
  return hops;
}

tests:
if (countHops([2, 3, 1, 1, 4]) !== 4) throw new Error('4: ' + countHops([2, 3, 1, 1, 4]));
if (countHops([1, 1, 1]) !== 3) throw new Error('unit steps');
if (countHops([5]) !== 1) throw new Error('single');
if (countHops([1, 2, 3]) !== 2) throw new Error('mixed');

