function lastNonZero(a) {
  let i = a.length - 1;
  while (i >= 0 && a[i] === 0) i--;
  return i;
}

tests:
if (lastNonZero([0, 5, 0, 0]) !== 1) throw new Error('1');
if (lastNonZero([0, 0, 0]) !== -1) throw new Error('all zero');
if (lastNonZero([]) !== -1) throw new Error('empty');
if (lastNonZero([7]) !== 0) throw new Error('single');

