function partitionEvenOdd(a) {
  let w = 0;
  for (let i = 0; i < a.length; i++) {
    if (a[i] % 2 === 0) {
      [a[w], a[i]] = [a[i], a[w]];
      w++;
    }
  }
  return a;
}

tests:
const eq = (g, w) => { if (JSON.stringify(g) !== JSON.stringify(w)) throw new Error(JSON.stringify(g)); };
eq(partitionEvenOdd([1, 2, 3, 4, 5]), [2, 4, 3, 1, 5]);
eq(partitionEvenOdd([]), []);
eq(partitionEvenOdd([2, 4]), [2, 4]);
const r = partitionEvenOdd([4, 1, 6, 3, 8]);
if (!(r.slice(0, 3).every(x => x % 2 === 0) && r.slice(3).every(x => x % 2 === 1))) throw new Error('split: ' + r);

