solution:
function sortedIntersection(A, B) {
  let i = 0, j = 0;
  const out = [];
  while (i < A.length && j < B.length) {
    if (A[i] === B[j]) { out.push(A[i]); i++; j++; }
    else if (A[i] < B[j]) i++;
    else j++;
  }
  return out;
}

