function compress(s) {
  let i = 0;
  let res = '';
  while (i < s.length) {
    let j = i;
    while (j < s.length && s[j] === s[i]) j++;
    res += s[i];
    if (j - i > 1) res += (j - i);
    i = j;
  }
  return res;
}

tests:
if (compress('aaabbc') !== 'a3b2c') throw new Error(compress('aaabbc'));
if (compress('') !== '') throw new Error('empty');
if (compress('abc') !== 'abc') throw new Error('distinct');
if (compress('aabb') !== 'a2b2') throw new Error('pairs');
if (compress('a') !== 'a') throw new Error('single');

